const FB_PAGE_ID = 'REPLACE_WITH_FB_PAGE_ID';
const FB_ACCESS_TOKEN = 'REPLACE_WITH_FB_PAGE_TOKEN';

return [{
  json: {
    url: `https://graph.facebook.com/v19.0/${FB_PAGE_ID}/posts?fields=id,message,created_time&limit=10&access_token=${FB_ACCESS_TOKEN}`,
    fb_page_id: FB_PAGE_ID,
    fb_token: FB_ACCESS_TOKEN
  }
}];

const response = $input.first().json;
const fbToken = $('Build FB Comments Request').first().json.fb_token;
const posts = response.data || [];

return posts.map(post => ({
  json: {
    post_id: post.id,
    url: `https://graph.facebook.com/v19.0/${post.id}/comments?fields=id,from,message,created_time&limit=20&access_token=${fbToken}`,
    fb_token: fbToken
  }
}));

const allItems = $input.all();
const comments = [];

for (const item of allItems) {
  const data = item.json.data || [];
  for (const comment of data) {
    if (!comment.message || comment.message.trim().length < 3) continue;
    comments.push({
      platform_comment_id: comment.id,
      commenter_name: (comment.from && comment.from.name) ? comment.from.name : 'Unknown',
      comment_text: comment.message.substring(0, 1000)
    });
  }
}

const seen = new Set();
const uniqueComments = comments.filter(c => {
  if (seen.has(c.platform_comment_id)) return false;
  seen.add(c.platform_comment_id);
  return true;
});

return [{ json: { comments: uniqueComments, count: uniqueComments.length } }];

const repliedItems = $input.all();
const repliedIds = new Set(
  repliedItems.map(item => item.json.platform_comment_id).filter(Boolean)
);

const allComments = $('Extract Comments').first().json.comments || [];
const newComments = allComments.filter(c => !repliedIds.has(c.platform_comment_id));

return [{ json: { new_comments: newComments, count: newComments.length } }];

const data = $input.first().json;
const comments = data.new_comments || [];
return comments.map(c => ({ json: c }));

const ANTHROPIC_API_KEY = 'REPLACE_WITH_ANTHROPIC_KEY';
const comment = $input.first().json;

const systemPrompt = 'You are a community manager for Cameroon Concord, an independent Anglophone news platform. Reply to reader comments professionally, warmly, and briefly. Rules: Max 2 sentences. Never argue. Never discuss politics. Thank engagement. If the comment is hostile or offensive, reply calmly: "Thank you for reading Cameroon Concord." Return ONLY the reply text. No JSON. No preamble.';

const userPrompt = `Comment from ${comment.commenter_name}: "${comment.comment_text}"\n\nWrite a brief, professional reply:`;

const requestBody = JSON.stringify({
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 150,
  system: systemPrompt,
  messages: [{ role: 'user', content: userPrompt }]
});

return [{
  json: {
    api_key: ANTHROPIC_API_KEY,
    request_body: requestBody,
    platform_comment_id: comment.platform_comment_id,
    commenter_name: comment.commenter_name,
    comment_text: comment.comment_text
  }
}];

